/**
 * Unit tests for SubagentStart unified-dispatcher
 *
 * Tests input normalization (cwd → project_dir, agent_type → tool_input.subagent_type),
 * hookEventName inclusion in hookSpecificOutput, and context injection.
 */

import { describe, test, expect, vi, beforeEach } from 'vitest';
import type { HookInput } from '../../types.js';
import { mockCommonBasic } from '../fixtures/mock-common.js';

// =============================================================================
// Mocks - MUST be defined BEFORE imports
// =============================================================================

vi.mock('../../lib/common.js', () => mockCommonBasic());

vi.mock('../../subagent-start/context-gate.js', () => ({
  contextGate: vi.fn(() => ({ continue: true })),
}));

vi.mock('../../subagent-start/subagent-validator.js', () => ({
  subagentValidator: vi.fn(() => ({ continue: true, suppressOutput: true })),
}));

vi.mock('../../subagent-start/issue-context-injector.js', () => ({
  issueContextInjector: vi.fn(() => ({ continue: true, suppressOutput: true })),
}));

vi.mock('../../lib/agent-attribution.js', () => ({
  recordAgentStart: vi.fn(),
}));

import { unifiedSubagentStartDispatcher, registeredHookNames } from '../../subagent-start/unified-dispatcher.js';
import { contextGate } from '../../subagent-start/context-gate.js';
import { subagentValidator } from '../../subagent-start/subagent-validator.js';
import { issueContextInjector } from '../../subagent-start/issue-context-injector.js';
import { recordAgentStart } from '../../lib/agent-attribution.js';
import { createTestContext } from '../fixtures/test-context.js';

// =============================================================================
// Helpers
// =============================================================================

function input(overrides: Partial<HookInput> = {}): HookInput {
  return {
    session_id: 'test-session',
    tool_name: '',
    tool_input: { subagent_type: 'ork:test-generator', description: 'Run tests' },
    ...overrides,
  } as HookInput;
}

// =============================================================================
// Tests
// =============================================================================

let testCtx: ReturnType<typeof createTestContext>;
describe('unified-subagent-start-dispatcher', () => {
  beforeEach(() => {
    testCtx = createTestContext();
    vi.clearAllMocks();
  });

  describe('hook registry', () => {
    test('registered hooks include all phases', () => {
      const names = registeredHookNames();
      expect(names).toContain('context-gate');
      expect(names).toContain('subagent-validator');
      expect(names).toContain('issue-context-injector');
    });
  });

  describe('silent success (no context)', () => {
    test('returns silent success when no context produced', () => {
      const result = unifiedSubagentStartDispatcher(input());
      expect(result.continue).toBe(true);
      expect(result.suppressOutput).toBe(true);
    });

    test('calls context-gate, validator, and context hooks', () => {
      unifiedSubagentStartDispatcher(input());
      expect(contextGate).toHaveBeenCalled();
      expect(subagentValidator).toHaveBeenCalled();
      expect(issueContextInjector).toHaveBeenCalled();
    });
  });

  describe('context injection with hookEventName', () => {
    test('includes hookEventName: SubagentStart in hookSpecificOutput', () => {
      // Make subagentValidator return context
      vi.mocked(subagentValidator).mockReturnValueOnce({
        continue: true,
        hookSpecificOutput: {
          additionalContext: 'Permission profile: elevated risk',
        },
      });

      const result = unifiedSubagentStartDispatcher(input());
      expect(result.hookSpecificOutput).toBeDefined();
      expect(result.hookSpecificOutput!.hookEventName).toBe('SubagentStart');
      expect(result.hookSpecificOutput!.additionalContext).toContain('Permission profile');
    });

    test('includes hookEventName when issue context is injected', () => {
      vi.mocked(issueContextInjector).mockReturnValueOnce({
        continue: true,
        hookSpecificOutput: {
          additionalContext: 'Issue #123: Fix login bug',
        },
      });

      const result = unifiedSubagentStartDispatcher(input());
      expect(result.hookSpecificOutput?.hookEventName).toBe('SubagentStart');
      expect(result.hookSpecificOutput?.additionalContext).toContain('Issue #123');
    });
  });

  describe('blocking by context-gate', () => {
    test('returns gate result when blocked', () => {
      vi.mocked(contextGate).mockReturnValueOnce({
        continue: false,
        stopReason: 'Too many concurrent agents',
      });

      const result = unifiedSubagentStartDispatcher(input());
      expect(result.continue).toBe(false);
      expect(result.stopReason).toBe('Too many concurrent agents');
    });

    test('does not call validator or context hooks when blocked', () => {
      vi.mocked(contextGate).mockReturnValueOnce({ continue: false });

      unifiedSubagentStartDispatcher(input());
      expect(subagentValidator).not.toHaveBeenCalled();
      expect(issueContextInjector).not.toHaveBeenCalled();
    });
  });

  describe('agent attribution', () => {
    test('records agent start when agent_id present', () => {
      unifiedSubagentStartDispatcher(input({ agent_id: 'agent-abc123' }));
      expect(recordAgentStart).toHaveBeenCalledWith('agent-abc123');
    });

    test('skips attribution when no agent_id', () => {
      unifiedSubagentStartDispatcher(input({ agent_id: undefined }));
      expect(recordAgentStart).not.toHaveBeenCalled();
    });
  });

  describe('error resilience', () => {
    test('returns silent success when context-gate throws', () => {
      vi.mocked(contextGate).mockImplementationOnce(() => { throw new Error('boom'); });
      const result = unifiedSubagentStartDispatcher(input());
      expect(result.continue).toBe(true);
    });

    test('returns silent success when validator throws', () => {
      vi.mocked(subagentValidator).mockImplementationOnce(() => { throw new Error('boom'); });
      const result = unifiedSubagentStartDispatcher(input());
      expect(result.continue).toBe(true);
    });
  });
});
